module "avm_nat_gateway" {
  source  = "Azure/avm-res-network-natgateway/azurerm"
  version = "0.2.1" # Pinning to a specific version

  name                    = local.nat_gateway_name
  location                = data.azurerm_resource_group.packer_rg.location
  resource_group_name     = data.azurerm_resource_group.packer_rg.name
  idle_timeout_in_minutes = var.nat_gateway_idle_timeout_in_minutes
  sku_name                = "Standard" // This is the default for the module, but explicit for clarity
  tags                    = local.common_tags
  enable_telemetry        = false
  // ADR: zones = null deploys a non-zonal (regional) NAT Gateway. This is acceptable for
  // dev environment. For production, set zones = ["1","2","3"] on NAT GW, PIP, and IP prefix
  // to ensure zone-redundant outbound connectivity. All three resources MUST share the same
  // zone configuration to avoid deployment failures. (C2 review fix)
  zones = null

  // Explicitly disable module-internal IP prefix creation since we manage the prefix
  // externally in main.tf. Prevents accidental dual-prefix association. (C2-Copilot review fix)
  public_ip_prefix_length = 0

  // Configure the module to create one Public IP
  public_ips = {
    "packer_image_natg_pip" = { // Arbitrary key for Terraform to track this specific IP
      name = local.nat_gateway_pip_name
    }
  }

  // Configure properties for the Public IP(s) created by the module
  // NOTE: public_ip_configuration applies globally to ALL PIPs created by the module.
  // Currently only one PIP (packer_image_natg_pip) is defined.
  // NOTE: inherit_tags is declared in AVM v0.2.1 variables but NOT implemented in module logic.
  // Tags propagate to the PIP via fallback: when public_ip_configuration.tags is null (default),
  // the module uses var.tags (our local.common_tags). Do NOT set public_ip_configuration.tags = {}
  // or HIPAA compliance tags will be lost. (C1 multi-LLM review fix)
  public_ip_configuration = {
    allocation_method       = var.nat_gateway_pip_allocation_method
    sku                     = var.nat_gateway_pip_sku
    zones                   = var.nat_gateway_pip_zones
    ddos_protection_mode    = var.nat_gateway_pip_ddos_protection_mode
    idle_timeout_in_minutes = var.nat_gateway_pip_idle_timeout_in_minutes
  }
}

// Workaround: AVM NAT GW module v0.2.1 does not support public_ip_prefixes natively.
// The prefix is managed externally in main.tf and associated here.
// TODO: Migrate to module-native prefix support when available. (M4 review fix)
resource "azurerm_nat_gateway_public_ip_prefix_association" "natg_prefix" {
  nat_gateway_id      = module.avm_nat_gateway.resource_id
  public_ip_prefix_id = azurerm_public_ip_prefix.packer_image_natg_ipprefix.id
}

resource "azurerm_public_ip_prefix" "packer_image_natg_ipprefix" {
  tags                = local.common_tags
  sku_tier            = "Regional"
  sku                 = "Standard"
  resource_group_name = data.azurerm_resource_group.packer_rg.name
  prefix_length       = var.nat_gateway_pip_prefix_length
  name                = local.nat_gateway_pip_prefix_name
  location            = data.azurerm_resource_group.packer_rg.location
  ip_version          = "IPv4"
  // ADR: zones must align with NAT GW and PIP. Null = non-zonal (regional) for dev.
  // For production, set to ["1","2","3"] alongside NAT GW and PIP zones. (C3 review fix)
  zones = null

  lifecycle {
    // IP prefix allocates public IPs from Azure. Destroying releases IPs permanently.
    // If these IPs are allowlisted at firewalls or third-party services, destruction is
    // catastrophic. Requires explicit removal of this block before destroy. (C4 review fix)
    prevent_destroy = true
  }
}

// M3 review fix: renamed resource label from hyphens to underscores for HashiCorp conventions
moved {
  from = azurerm_public_ip_prefix.packer-image-natg-ipprefix
  to   = azurerm_public_ip_prefix.packer_image_natg_ipprefix
}

# Network Configuration
# Azure CLI
# ## Create myVNet virtual network with the default address space: 10.0.0.0/16. ##
# az network vnet create --resource-group rg-hypera-packer-image --name vnet-wip-0 --address-prefix 10.248.7.0/14 --subnet-name mySubnet --subnet-prefix 10.248.7.0/24

module "virtualnetwork" {
  source  = "Azure/avm-res-network-virtualnetwork/azurerm"
  version = "~> 0.2"

  # enable_telemetry    = false

  name                = local.vnet_name
  location            = data.azurerm_resource_group.packer_rg.location
  resource_group_name = data.azurerm_resource_group.packer_rg.name
  address_space       = var.vnet_address_space
  tags                = local.common_tags

  subnets = {
    GatewaySubnet = {
      name             = "GatewaySubnet"
      address_prefixes = var.vnet_subnet_gateway
    }

    AzureBastionSubnet = {
      name             = "AzureBastionSubnet"
      address_prefixes = var.vnet_azure_subnet_bastion
      network_security_group = {
        id = module.bastion_nsg_avm.resource_id
      }
    }

    // ADR: NAT Gateway is intentionally associated with PublicSubnet to provide deterministic
    // outbound IPs for allowlisting. Note: if VMs in PublicSubnet have instance-level PIPs,
    // NAT GW takes precedence for outbound (asymmetric routing). This is the desired behavior
    // for this project — all outbound traffic uses the NAT GW's static IP. (M1 review fix)
    PublicSubnet = {
      name             = local.subnet_public_name
      address_prefixes = var.vnet_subnet_public
      network_security_group = {
        id = module.public_nsg_avm.resource_id
      }
      nat_gateway = {
        id = module.avm_nat_gateway.resource_id
      }

      service_endpoints = [
        "Microsoft.ContainerRegistry",
        "Microsoft.KeyVault",
        "Microsoft.ServiceBus",
        "Microsoft.Storage"
      ]
    }

    // M5 review fix: Added service endpoints to prevent PII/PHI traffic from traversing
    // the public internet when reaching Azure PaaS services. Without these, all traffic
    // from PrivateSubnet routes through NAT Gateway over the public path. (Gemini review)
    PrivateSubnet = {
      name             = local.subnet_private_name
      address_prefixes = var.vnet_subnet_private

      network_security_group = {
        id = module.private_nsg_avm.resource_id
      }
      nat_gateway = {
        id = module.avm_nat_gateway.resource_id
      }

      service_endpoints = [
        "Microsoft.ContainerRegistry",
        "Microsoft.KeyVault",
        "Microsoft.Storage"
      ]
    }
  }
}

