# Basic Azure Configuration
variable "resource_group_name" {
  type        = string
  description = "Name of the Azure Resource Group"
}

variable "location" {
  type        = string
  description = "Azure region for resource deployment"
}

variable "environment" {
  type        = string
  description = "Environment name (e.g., dev, prod)"
  default     = "dev"
}

variable "azure_region_shortcode" {
  type        = string
  description = "Short code for Azure region (e.g., eus2)"
}

# Bastion Host Configuration
variable "bastion_sku" {
  type        = string
  description = "SKU for the Azure Bastion host"
  default     = "Basic"
}

# VM Configuration
variable "vm_sku" {
  type        = string
  description = "Size of the Azure VM"
}

variable "vm_name" {
  type        = string
  description = "Name of the Azure VM"
}

variable "custom_image_name" {
  type        = string
  description = "Name of the custom image to use for VM"
}

variable "vm_admin_username" {
  type        = string
  description = "Username for VM administrator"
}

variable "admin_ssh_key_username" {
  type        = string
  description = "Username for SSH key authentication"
}

variable "admin_public_key_path" {
  type        = string
  description = "Path to the public SSH key file"
}

# Network Configuration
variable "vnet_address_space" {
  type        = list(string)
  description = "Address space for the virtual network"
}

variable "vnet_subnet_gateway" {
  type        = list(string)
  description = "Address space for the gateway subnet"
}

variable "vnet_subnet_public" {
  type        = list(string)
  description = "Address space for the public subnet"
}

variable "vnet_azure_subnet_bastion" {
  type        = list(string)
  description = "Address space for the Azure Bastion subnet"
}

variable "vnet_subnet_private" {
  type        = list(string)
  description = "Address space for the private subnet"
}

variable "vm_private_ip_address" {
  type        = list(string)
  description = "Private IP address for the VM"
}

# Integration Configuration
variable "msteams_channel" {
  type        = string
  description = "Microsoft Teams webhook URL for notifications"
}

variable "boot_diagnostics_storage_uri" {
  type        = string
  description = "Storage account URI for boot diagnostics"
}

# Image Reference
variable "custom_image_id" {
  type        = string
  description = "Resource ID of the custom VM image"
}

# Security Rules
variable "private_security_rules" {
  type = list(object({
    name                       = string
    priority                   = number
    direction                  = string
    access                     = string
    protocol                   = string
    source_port_range          = string
    destination_port_range     = string
    source_address_prefix      = string
    destination_address_prefix = string
    description                = optional(string)
  }))
  description = "Security rules for private network"
}

variable "public_security_rules" {
  type = list(object({
    name                       = string
    priority                   = number
    direction                  = string
    access                     = string
    protocol                   = string
    source_port_range          = string
    destination_port_range     = string
    source_address_prefix      = string
    destination_address_prefix = string
    description                = optional(string)
  }))
  description = "Security rules for public network"
}

variable "hypera_cidr_ips" {
  description = "ip list for our infra"
  type        = list(string)
  default = [
    "187.120.4.0/27",
    "187.120.4.32/30",
    "187.120.6.208/30",
    "20.157.24.4/32",
    "200.174.104.208/28",
    "200.183.39.176/29",
    "200.230.54.128/25",
    "201.87.143.0/25",
  ]
}


# NAT Gateway Public IP Configuration
variable "nat_gateway_pip_prefix_length" {
  type        = number
  description = "Prefix length for the NAT Gateway Public IP. Azure accepts 28-31."
  default     = 30

  validation {
    condition     = contains([28, 29, 30, 31], var.nat_gateway_pip_prefix_length)
    error_message = "Prefix length must be 28, 29, 30, or 31 for Azure public IP prefixes."
  }
}

variable "nat_gateway_pip_sku" {
  type        = string
  description = "SKU for the NAT Gateway Public IP. NAT Gateway requires Standard."
  default     = "Standard"

  validation {
    condition     = var.nat_gateway_pip_sku == "Standard"
    error_message = "NAT Gateway public IP must use Standard SKU."
  }
}

variable "nat_gateway_pip_allocation_method" {
  type        = string
  description = "Allocation method for the NAT Gateway Public IP. Standard SKU requires Static."
  default     = "Static"

  validation {
    condition     = var.nat_gateway_pip_allocation_method == "Static"
    error_message = "Standard SKU public IPs require Static allocation method."
  }
}

variable "nat_gateway_idle_timeout_in_minutes" {
  type        = number
  description = "Idle timeout in minutes for the NAT Gateway itself. Controls SNAT port release. Azure accepts 4-120."
  default     = 4

  validation {
    condition     = var.nat_gateway_idle_timeout_in_minutes >= 4 && var.nat_gateway_idle_timeout_in_minutes <= 120
    error_message = "NAT Gateway idle timeout must be between 4 and 120 minutes."
  }
}

variable "nat_gateway_pip_zones" {
  type        = list(string)
  description = "Availability zones for the NAT Gateway Public IP. Empty list [] for non-zonal, or list of zone numbers. Must align with NAT Gateway and IP prefix zones."
  default     = []
  nullable    = false
}

variable "nat_gateway_pip_ddos_protection_mode" {
  type        = string
  description = "DDoS protection mode for the NAT Gateway Public IP."
  default     = "VirtualNetworkInherited"

  validation {
    condition     = contains(["Disabled", "Enabled", "VirtualNetworkInherited"], var.nat_gateway_pip_ddos_protection_mode)
    error_message = "DDoS protection mode must be Disabled, Enabled, or VirtualNetworkInherited."
  }
}

variable "nat_gateway_pip_idle_timeout_in_minutes" {
  type        = number
  description = "Idle timeout in minutes for the NAT Gateway Public IP. For NAT GW-associated PIPs, this is effectively irrelevant as the NAT GW timeout governs SNAT. Azure accepts 4-30."
  default     = 4

  validation {
    condition     = var.nat_gateway_pip_idle_timeout_in_minutes >= 4 && var.nat_gateway_pip_idle_timeout_in_minutes <= 30
    error_message = "Idle timeout must be between 4 and 30 minutes."
  }
}
